def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    factor = np.sqrt(abs(ratio - a)) / (a + b * 0.7 + 1)
                    priority += factor * np.tan(ratio * b / (a + 2)) - np.exp(-b / (ratio + 1))
            priority += np.tanh(ratio - 7) * 15 - np.sin(ratio * 2.5) ** 2
        elif 5 < ratio <= 8:
            for c in range(1, int(np.ceil(ratio)) + 5):
                for d in range(c, c + 4):
                    term = ((ratio - c) ** 4) * np.cos(ratio * d * 0.8) / (d + 1)
                    priority += np.log1p(abs(term)) * np.sin(d * np.pi / 7)
            priority += np.exp(-ratio) * 8 + np.abs(np.cos(ratio * 4)) * 4
        elif 2 <= ratio <= 5:
            s = 0
            for e in range(1, 20):
                s += ((ratio - 2) ** (e / 2)) / (e + 0.5) * np.sin(e * ratio * 1.3)
            priority = s + np.cos(ratio * 7) * 6 - np.sqrt(ratio) * 5
            if bin_cap < item * 2:
                priority += np.log1p(bin_cap) * 3
            else:
                priority -= np.sin(bin_cap) * 2
        elif 1 <= ratio < 2:
            s = 0
            for f in range(1, 8):
                s += ((2 - ratio) ** f) / (f * 1.5 + 0.3) * np.cos(f * ratio * 2.7)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.tan(item / (bin_cap + 1)) * 6
            else:
                penalty = np.cos(15 * ratio) * 4
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for g in range(1, 7):
                priority += np.sin(g * ratio * i) * ((ratio - 1) ** g) / g * 1.1
        elif 0.5 <= ratio < 1:
            s = 0
            for h in range(1, 18):
                s += ((1 - ratio) ** h) / (h ** 1.8 + 0.7) * np.cos(h * item * 0.9)
            priority = s
            if (i + int(item * 2.3)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.cbrt(bin_cap + 2) + 1.5)
            for j in range(1, 9):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 3.1)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 2.7) % 6 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 5.2
            else:
                priority -= np.exp(-ratio * 1.7) * 4.5
            for l in range(1, 8):
                priority += ((0.5 - ratio) ** l) / (l * 5) * np.cos(item * l * 1.3)
        else:
            s = 0
            for m in range(1, 12):
                s += ((0.2 - ratio) ** m) / (m * 4.5) * np.sin(m * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 1.2) % 7 == 0:
                priority *= 3.7
            else:
                priority /= 3.7
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.3) * 5
            for n in range(1, 10):
                priority += ((0.2 - ratio) ** n) / (n * 6) * np.cos(item * n * 0.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5
        for o in range(1, 6):
            if (i + o * 2) % 5 == 0:
                priority += np.sin(ratio * (i + o)) * 0.4
            else:
                priority -= np.cos(ratio * (i + o)) * 0.4
            if i % 2 == 0:
                priority += np.cos(ratio * i * o) * 0.5
            else:
                priority -= np.sin(ratio * i * o) * 0.5
        if i % 5 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
